PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?book ?bookLabel ?publicationDate
WHERE {
  ?book wdt:P50 wd:Q62894817;
        wdt:P31/wdt:P279* wd:Q7725634;  # Instance of book
        wdt:P577 ?publicationDate.
  OPTIONAL { ?book rdfs:label ?bookLabel FILTER (LANG(?bookLabel) = "en") }
}
ORDER BY ?publicationDate
LIMIT 10

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?book ?title ?publicationDate
WHERE {
  ?book wdt:P50 wd:Q62894817;
        wdt:P31/wdt:P279* wd:Q7725634;
        wdt:P1476 ?title;
        wdt:P577 ?publicationDate.
  FILTER CONTAINS(LCASE(?title), "extraordinary union")
  FILTER(LANG(?title) = "en")
}
ORDER BY ?publicationDate
LIMIT 1

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?book ?title ?publicationDate
WHERE {
  ?book wdt:P50 wd:Q62894817;
        wdt:P179/wdt:rdfs:label ?seriesLabel;
        wdt:P1476 ?title;
        wdt:P577 ?publicationDate.
  FILTER REGEX(LCASE(?seriesLabel), "loyal league")
  FILTER(LANG(?title) = "en")
}
ORDER BY ?publicationDate
LIMIT 1
